import subprocess
import sys
import os
import json
import shutil
import platform
import re
from urllib.request import urlopen, Request
from urllib.parse import quote

# Utility functions
def which(cmd):
    return shutil.which(cmd) is not None

def run(cmd, timeout=60):
    try:
        p = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, timeout=timeout, text=True)
        return p.stdout, p.stderr, p.returncode
    except Exception as e:
        return "", str(e), 1

def banner(msg):
    print("\n" + "="*80)
    print(msg)
    print("="*80 + "\n")

def parse_service_versions():
    services = []
    # Try common commands to extract service versions
    checks = [
        ("openssl", ["openssl", "version"]),
        ("nginx", ["nginx", "-v"]),
        ("apache", ["apachectl", "-v"]),
        ("httpd", ["httpd", "-v"]),
        ("ssh", ["ssh", "-V"]),
        ("docker", ["docker", "--version"]),
        ("kubelet", ["kubelet", "--version"]),
        ("kubectl", ["kubectl", "version", "--client", "--output=json"]),
        ("python", [sys.executable, "--version"]),
        ("node", ["node", "--version"]),
        ("npm", ["npm", "--version"]),
        ("java", ["java", "-version"]),
        ("postgres", ["psql", "--version"]),
        ("mysql", ["mysql", "--version"]),
        ("redis", ["redis-server", "--version"]),
    ]
    for name, cmd in checks:
        if which(cmd[0]):
            out, err, rc = run(cmd)
            text = (out + err).strip()
            if text:
                services.append((name, text))
    return services

def parse_kernel_info():
    return {
        "system": platform.system(),
        "release": platform.release(),
        "version": platform.version(),
        "machine": platform.machine()
    }

def search_cve(product, version_str):
    # Use NIST NVD API v2 (no key fallback, limited rate)
    # Simplify by constructing keyword query
    q = f"{product} {version_str}"
    url = f"https://services.nvd.nist.gov/rest/json/cves/2.0?keywordSearch={quote(q)}&resultsPerPage=10"
    try:
        req = Request(url, headers={"User-Agent": "SecScanner/1.0"})
        with urlopen(req, timeout=15) as resp:
            data = json.load(resp)
        items = data.get("vulnerabilities", [])
        cves = []
        for item in items:
            cve = item.get("cve", {})
            id_ = cve.get("id")
            descs = cve.get("descriptions", [])
            desc = descs[0]["value"] if descs else ""
            metrics = cve.get("metrics", {})
            cvss = None
            for key in ("cvssMetricV31", "cvssMetricV30", "cvssMetricV2"):
                if key in metrics and metrics[key]:
                    cvss = metrics[key][0].get("cvssData", {}).get("baseScore")
                    break
            cves.append({"id": id_, "description": desc, "cvss": cvss})
        return cves
    except Exception:
        return []

def check_common_misconfigs():
    findings = []
    # SSH root login
    sshd_config = "/etc/ssh/sshd_config"
    if os.path.exists(sshd_config):
        try:
            with open(sshd_config, "r", encoding="utf-8", errors="ignore") as f:
                content = f.read()
            m = re.search(r"^\s*PermitRootLogin\s+(\S+)", content, re.MULTILINE)
            if m and m.group(1).lower() not in ("no", "prohibit-password"):
                findings.append({"area": "ssh", "issue": "PermitRootLogin not disabled", "file": sshd_config})
            if "PasswordAuthentication yes" in content:
                findings.append({"area": "ssh", "issue": "PasswordAuthentication enabled", "file": sshd_config})
        except Exception:
            pass
    # World-writable files in system paths
    dirs = ["/etc", "/usr/local/bin", "/usr/bin", "/var/www", "/opt"]
    for d in dirs:
        if os.path.isdir(d):
            try:
