    if os.path.exists("/var/run/docker.sock"):
        findings.append({"area": "docker", "issue": "Docker socket accessible", "file": "/var/run/docker.sock"})
    return findings

def scan_dependencies(path):
    deps = []
    # Python requirements
    reqs = os.path.join(path, "requirements.txt")
    if os.path.exists(reqs):
        try:
            with open(reqs, "r", encoding="utf-8", errors="ignore") as f:
                for line in f:
                    line = line.strip()
                    if not line or line.startswith("#"):
                        continue
                    deps.append(("python", line))
        except Exception:
            pass
    # Node/package.json
    pkg_json = os.path.join(path, "package.json")
    if os.path.exists(pkg_json):
        try:
            with open(pkg_json, "r", encoding="utf-8", errors="ignore") as f:
                pj = json.load(f)
            for section in ("dependencies", "devDependencies"):
                for name, version in (pj.get(section) or {}).items():
                    deps.append(("node", f"{name}@{version}"))
        except Exception:
            pass
    return deps

