* { box-sizing: border-box; }
body {
  margin: 0;
  font-family: system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, Arial, sans-serif;
  background: linear-gradient(180deg, var(--bg), #0b1220);
  color: var(--fg);
  line-height: 1.6;
}
.container {
  width: min(1100px, 92%);
  margin: 0 auto;
}
.site-header {
  position: sticky; top: 0; backdrop-filter: blur(8px);
  background: rgba(15, 23, 42, 0.6);
  border-bottom: 1px solid rgba(99, 102, 241, 0.2);
  z-index: 10;
}
.site-header .container { display: flex; align-items: center; justify-content: space-between; padding: 14px 0; }
.site-header h1 { font-size: 1.2rem; margin: 0; letter-spacing: 0.5px; }
nav ul { list-style: none; display: flex; gap: 18px; margin: 0; padding: 0; }
nav a { color: var(--fg); text-decoration: none; opacity: 0.9; }
nav a:hover { color: var(--accent); }
.hero {
  padding: 72px 0 36px;
  text-align: center;
  background: radial-gradient(1000px 400px at 50% -10%, rgba(99,102,241,0.25), transparent);
}
.hero h2 { font-size: 2.2rem; margin: 0 0 10px; }
.hero p { margin: 0 0 18px; color: var(--muted); }
.btn {
  background: var(--accent);
  color: white;
  border: none;
  padding: 12px 18px;
  border-radius: 8px;
  cursor: pointer;
  transition: transform 0.08s ease, box-shadow 0.2s ease, background 0.2s ease;
  box-shadow: 0 10px 25px rgba(99, 102, 241, 0.35);
}
.btn:hover { transform: translateY(-1px); }
.section { padding: 48px 0; }
.section.alt { background: var(--alt); }
h3 { margin: 0 0 14px; }
.grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 18px;
}
.card {
  background: var(--card);
  border: 1px solid rgba(148, 163, 184, 0.16);
  border-radius: 12px;
  padding: 18px;
}
.card h4 { margin: 0 0 8px; }
.card p { color: var(--muted); margin: 0 0 10px; }
.link { color: var(--accent); text-decoration: none; }
.resource-list { padding-left: 18px; }
.form { margin-top: 10px; }
.input-row { display: flex; gap: 10px; }
input[type="email"] {
  flex: 1; padding: 12px; border-radius: 8px; border: 1px solid rgba(148,163,184,0.25);
  background: #0b1020; color: var(--fg);
}
.form-message { margin-top: 8px; color: var(--muted); min-height: 1.2em; }
.site-footer { border-top: 1px solid rgba(99, 102, 241, 0.2); padding: 22px 0; margin-top: 36px; text-align: center; color: var(--muted); }

