type BusinessProfile = {
  name: string;
  category: string;
  location?: string;
  specialties?: string[];
  highlights?: string[];
  priceRange?: "$" | "$$" | "$$$" | "$$$$";
  hours?: string;
  website?: string;
  contact?: string;
};

type ReviewPersona = {
  displayName?: string;
  visitContext?: string; // e.g., "anniversary dinner"
  expertiseLevel?: "novice" | "regular" | "enthusiast" | "expert";
  preferences?: string[]; // e.g., "fast service", "vegan options"
  sentiment: 1 | 2 | 3 | 4 | 5;
  tone: "casual" | "professional" | "enthusiastic" | "concise";
  language?: string; // "en", "es", etc.
  locale?: string; // "en-US", "en-GB"
};

type PlatformStyle = {
  name: "Google" | "Yelp" | "Facebook" | "Generic";
  charLimit?: number;
  allowEmojis?: boolean;
  allowHashtags?: boolean;
  prohibitedPhrases?: string[];
  requiresHeadline?: boolean;
};

type GenerationConfig = {
  creativity?: number; // 0..1
  length?: "short" | "medium" | "long";
  variants?: number;
  includeProsCons?: boolean;
  includeTips?: boolean;
  includeSuggestions?: boolean;
  includeHeadline?: boolean;
  includeStarSymbols?: boolean;
  maskWordTag?: string; // default "{MASK_WORD}"
};

type GeneratedReview = {
  headline?: string;
  body: string;
  stars: number;
  platform: string;
  tags?: string[];
  note?: string; // e.g., "generated sample"
};

