function planContent(profile: BusinessProfile, persona: ReviewPersona, cfg: GenerationConfig) {
  // Select 2–3 details to mention based on specialties/highlights/preferences
  const details: string[] = [];
  const prefs = persona.preferences ?? [];
  const pool = (profile.highlights ?? []).concat(profile.specialties ?? []);
  for (const p of pool) {
    if (prefs.length && prefs.some(x => p.toLowerCase().includes(x.toLowerCase()))) {
      details.push(p);
    }
  }
  for (const p of pool) {
    if (!details.includes(p) && details.length < 3) details.push(p);
  }
  return details.slice(0, 3);
}

function toneTransform(text: string, persona: ReviewPersona, plat: PlatformStyle): string {
  // Simplified: strip emojis if not allowed, adjust punctuation density if professional/concise
  if (!plat.allowEmojis) {
    text = text.replace(/\p{Extended_Pictographic}/gu, "");
  }
  if (persona.tone === "concise") {
    text = text.replace(/\s{2,}/g, " ");
  }
  return text.trim();
}

function truncateToLimit(text: string, limit?: number): string {
  if (!limit || text.length <= limit) return text;
  // Try to cut at sentence boundary
  const cut = text.slice(0, limit - 1);
  const lastPeriod = cut.lastIndexOf(".");
  return (lastPeriod > 40 ? cut.slice(0, lastPeriod + 1) : cut) + (text.length > cut.length ? "…" : "");
}

function buildBody(profile: BusinessProfile, persona: ReviewPersona, details: string[], cfg: GenerationConfig, plat: PlatformStyle): string {
  const starMap = {1:"★☆☆☆☆",2:"★★☆☆☆",3:"★★★☆☆",4:"★★★★☆",5:"★★★★★"};
  const stars = cfg.includeStarSymbols ? starMap[persona.sentiment] + " " : "";
  const openings = {
    5: ["Outstanding experience at", "Absolutely loved", "Top-notch service at"],
    4: ["Great visit to", "Very pleased with", "Solid experience at"],
    3: ["Mixed feelings about", "It was okay at", "Average experience at"],
    2: ["Disappointed with", "Not the best at", "Below expectations at"],
    1: ["Very poor experience at", "Wouldn’t recommend", "Frustrating time at"]
  } as const;

  const closings = {
    5: ["Highly recommend.", "Will definitely be back!", "Worth every penny."],
    4: ["Would recommend.", "I’d return with a few tweaks.", "Good value overall."],
    3: ["Could be better with improvements.", "Not rushing back, but not the worst.", "Room for improvement."],
    2: ["Hope they address these issues.", "Could improve with better consistency.", "Not great value this time."],
    1: ["I can’t recommend based on this visit.", "Would look elsewhere.", "Needs major improvements."]
  } as const;

  const open = openings[persona.sentiment][Math.floor(Math.random()*openings[persona.sentiment].length)];
  const close = closings[persona.sentiment][Math.floor(Math.random()*closings[persona.sentiment].length)];
  const namePart = profile.name ? profile.name : "this business";

  const detailStr = details.length ? "Highlights: " + details.join(", ") + "." : "";
  const contextStr = persona.visitContext ? `Context: ${persona.visitContext}. ` : "";

  let body = `${stars}${open} ${namePart}. ${contextStr}${detailStr} ${close}`;
  body = toneTransform(body, persona, plat);
  body = truncateToLimit(body, plat.charLimit);
  return body;
}

function generateReviews(profile: BusinessProfile, persona: ReviewPersona, platform: PlatformStyle, cfg: GenerationConfig = {}): GeneratedReview[] {
  const variants = Math.max(1, Math.min(10, cfg.variants ?? 3));
  const detailsPlan = planContent(profile, persona, cfg);
  const out: GeneratedReview[] = [];
  for (let i = 0; i < variants; i++) {
    const body = buildBody(profile, persona, detailsPlan, cfg, platform);
    const headline = cfg.includeHeadline || platform.requiresHeadline ? buildHeadline(profile, persona) : undefined;
    out.push({
      headline,
      body,
      stars: persona.sentiment,
      platform: platform.name,
      tags: [generateMaskWordTag(cfg)], // Tag with {MASK_WORD}
      note: "generated sample"
    });
  }
  return out;
}

function buildHeadline(profile: BusinessProfile, persona: ReviewPersona): string {
  const base = {
    5: ["Fantastic!", "Perfect visit", "Exceeded expectations"],
    4: ["Great experience", "Very good overall", "Would recommend"],
    3: ["Decent, with caveats", "Okay but room to improve", "Mixed bag"],
    2: ["Let down", "Needs improvement", "Below par"],
    1: ["Disappointing", "Not recommended", "Poor experience"]
  } as const;
  const pick = base[persona.sentiment][Math.floor(Math.random()*base[persona.sentiment].length)];
  return `${pick} at ${profile.name}`;
}

