import re

# Configuration: which fields are sensitive and how to handle them
SENSITIVE_FIELDS = {
    "ssn": "full",           # redact fully
    "email": "partial",      # keep first char and domain
    "phone": "partial",      # keep last 4 digits
    "credit_card": "fp",     # format-preserving: mask digits but keep grouping
    "address": "full",
    "name": "partial"
}

def mask_full(value: str) -> str:
    return "[REDACTED]"

def mask_partial_email(email: str) -> str:
    # Keep first character of local part and full domain
    try:
        local, domain = email.split("@", 1)
        if not local:
            return "[REDACTED]"
        return f"{local[0]}***@{domain}"
    except ValueError:
        return "[REDACTED]"

def mask_partial_phone(phone: str) -> str:
    digits = re.sub(r"\D", "", phone)
    if len(digits) < 4:
        return "[REDACTED]"
    masked = "***-***-" + digits[-4:]
    return masked

def mask_fp_credit_card(cc: str) -> str:
    # Preserve grouping (spaces or dashes), replace digits with X except last 4
    parts = re.split(r"(\D+)", cc)  # keep separators
    digits = re.sub(r"\D", "", cc)
    if len(digits) < 4:
        return "[REDACTED]"
    keep = digits[-4:]
    masked_digits = "X" * (len(digits) - 4) + keep
    # Reconstruct with original separators
    out = []
    idx = 0
    for p in parts:
        if p.isdigit():
            n = len(p)
            out.append(masked_digits[idx:idx+n])
            idx += n
        else:
            out.append(p)
    return "".join(out)

def mask_partial_name(name: str) -> str:
    # Keep first letter of each word, mask rest
    words = name.split()
    masked_words = []
    for w in words:
        if len(w) == 0:
            masked_words.append("")
        else:
            masked_words.append(w[0] + "*" * (len(w) - 1))
    return " ".join(masked_words)

def mask_value(field: str, value: str) -> str:
    strategy = SENSITIVE_FIELDS.get(field)
    if strategy == "full":
        return mask_full(value)
    elif strategy == "partial":
        if field == "email":
            return mask_partial_email(value)
        if field == "phone":
            return mask_partial_phone(value)
        if field == "name":
            return mask_partial_name(value)
        # generic partial: keep first and last char, mask middle
        if len(value) <= 2:
            return "[REDACTED]"
        return value[0] + "*" * (len(value) - 2) + value[-1]
    elif strategy == "fp":
        if field == "credit_card":
            return mask_fp_credit_card(value)
        return "[REDACTED]"
    else:
        # Not sensitive or unknown field
        return value

def process_record(record: dict, sensitive_fields=None) -> dict:
    """
    Returns a new record with sensitive fields masked.
    record: dict of field -> value
    sensitive_fields: optional override dict(field -> strategy)
    """
    strategies = SENSITIVE_FIELDS if sensitive_fields is None else sensitive_fields
    masked = {}
    for k, v in record.items():
        if v is None:
            masked[k] = None
            continue
        s = strategies.get(k)
        if s:
            masked[k] = mask_value(k, str(v))
        else:
            masked[k] = v
    return masked

# Example usage:
