        "name": "Jane Doe",
        "email": "jane.doe@example.com",
        "phone": "+1 (555) 123-4567",
        "credit_card": "4111-1111-1111-1234",
        "ssn": "123-45-6789",
        "address": "123 Main St, Springfield, IL",
        "notes": "Preferred customer"
    }
    masked = process_record(sample)
    for k, v in masked.items():
