import socket
import ssl
import json
import time
import threading
from contextlib import closing

# Optional: pip install zeroconf
try:
    from zeroconf import Zeroconf, ServiceBrowser
    ZEROCONF_AVAILABLE = True
except Exception:
    ZEROCONF_AVAILABLE = False

SSDP_MULTICAST = ("239.255.255.250", 1900)
COMMON_PORTS = [22, 23, 80, 443, 554, 8000, 8001, 8080, 8081, 8443]
SOCKET_TIMEOUT = 2.0

def tcp_connect(host, port, timeout=SOCKET_TIMEOUT):
    try:
        with closing(socket.create_connection((host, port), timeout)):
            return True
    except Exception:
        return False

def http_probe(host, port):
    try:
        with closing(socket.create_connection((host, port), SOCKET_TIMEOUT)) as s:
            req = f"GET / HTTP/1.1\r\nHost: {host}\r\nConnection: close\r\n\r\n"
            s.sendall(req.encode("ascii"))
            data = s.recv(4096).decode("latin-1", errors="ignore")
            return {"banner": data[:1000]}
    except Exception:
        return None

def tls_probe(host, port):
    ctx = ssl.create_default_context()
    ctx.check_hostname = False
    ctx.verify_mode = ssl.CERT_NONE
    try:
        with closing(socket.create_connection((host, port), SOCKET_TIMEOUT)) as raw:
            with closing(ctx.wrap_socket(raw, server_hostname=host)) as ssock:
                cipher = ssock.cipher()
                version = ssock.version()
                cert = ssock.getpeercert()
                return {"version": version, "cipher": cipher, "cert_subject": cert.get("subject", [])}
    except Exception:
        return None

def rtsp_probe(host, port=554):
    try:
        with closing(socket.create_connection((host, port), SOCKET_TIMEOUT)) as s:
            req = f"OPTIONS rtsp://{host}/ RTSP/1.0\r\nCSeq: 1\r\nUser-Agent: Probe\r\n\r\n"
            s.sendall(req.encode("ascii"))
            data = s.recv(4096).decode("latin-1", errors="ignore")
            return {"banner": data[:1000]}
    except Exception:
        return None

def ssdp_discover(timeout=2.0):
    results = []
    msg = "\r\n".join([
        "M-SEARCH * HTTP/1.1",
        f"HOST: {SSDP_MULTICAST[0]}:{SSDP_MULTICAST[1]}",
        "MAN: \"ssdp:discover\"",
        "MX: 1",
        "ST: ssdp:all",
        "", ""
    ]).encode("ascii")
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
    sock.settimeout(timeout)
    try:
        sock.sendto(msg, SSDP_MULTICAST)
        end = time.time() + timeout
        while time.time() < end:
            try:
                data, addr = sock.recvfrom(2048)
                results.append({"host": addr[0], "response": data.decode("latin-1", errors="ignore")})
            except socket.timeout:
                break
    finally:
        sock.close()
    return results

class ZCCollector:
    def __init__(self):
        self.services = []

    def add_service(self, zeroconf, type_, name):
        info = zeroconf.get_service_info(type_, name)
        if info and info.addresses:
            ip = socket.inet_ntoa(info.addresses[0])
            self.services.append({"type": type_, "name": name, "ip": ip})

def zeroconf_discover(timeout=3.0):
    if not ZEROCONF_AVAILABLE:
        return []
    zc = Zeroconf()
    collector = ZCCollector()
    types = ["_http._tcp.local.", "_hap._tcp.local.", "_ipps._tcp.local.", "_printer._tcp.local.", "_rtsp._tcp.local."]
    browsers = [ServiceBrowser(zc, t, handlers=[collector.add_service]) for t in types]
    time.sleep(timeout)
    zc.close()
    return collector.services

def assess_host(host):
    findings = {"host": host, "ports": {}, "checks": []}
    for port in COMMON_PORTS:
        if tcp_connect(host, port):
            findings["ports"][port] = {"open": True}
            # Probes
            if port in (80, 8080, 8000, 8001):
                hp = http_probe(host, port)
                if hp:
                    findings["ports"][port]["http"] = hp
                    banner = hp.get("banner", "")
                    if "Unauthorized" in banner or "WWW-Authenticate" in banner:
                        findings["checks"].append("HTTP auth enabled; verify strong passwords.")
                    if "Basic realm" in banner:
                        findings["checks"].append("Basic auth realm detected; check for default credentials.")
                    if "Server:" in banner and ("Boa" in banner or "lighttpd" in banner or "GoAhead" in banner):
                        findings["checks"].append("Embedded HTTP server detected; check firmware version for known CVEs.")
            if port == 443 or port == 8443:
                tp = tls_probe(host, port)
                if tp:
                    findings["ports"][port]["tls"] = tp
                    ver = tp.get("version", "")
                    if ver in ("TLSv1", "TLSv1.1", "SSLv3"):
                        findings["checks"].append("Outdated TLS version in use; upgrade to TLS 1.2+ or 1.3.")
            if port == 554:
                rp = rtsp_probe(host, port)
                if rp:
                    findings["ports"][port]["rtsp"] = rp
                    banner = rp.get("banner", "")
                    if "Public" in banner:
                        findings["checks"].append("RTSP enabled; verify authentication and network segmentation.")
            if port == 23:
                findings["checks"].append("Telnet open; disable and use SSH.")
            if port == 22:
                findings["checks"].append("SSH open; ensure key-based auth and disable password login.")
        else:
            findings["ports"][port] = {"open": False}
    return findings

def unique_hosts(ssdp_results, zc_results):
    hosts = set()
    for r in ssdp_results:
        hosts.add(r["host"])
    for r in zc_results:
        hosts.add(r["ip"])
    return list(hosts)

def scan_network():
    ssdp = ssdp_discover(timeout=3.0)
    zc = zeroconf_discover(timeout=3.0)
    hosts = unique_hosts(ssdp, zc)
    results = {"discovered_hosts": hosts, "assessments": []}
    for h in hosts:
        results["assessments"].append(assess_host(h))
    return results

if __name__ == "__main__":
    report = scan_network()
    print(json.dumps(report, indent=2))

How to use:
- Run on a trusted computer in the same network as your smart home devices.
- Ensure you have permission to assess devices.
- Optional: pip install zeroconf for mDNS discovery.
- Review the JSON report for open services and configuration risks.

Next steps:
